// Code: Nach Kunden aufteilen (v9)
// Feldname bestätigt: property_loeschen (kein Umlaut)
// Loeschen=true → loescheIds (unabhängig von ConfluenceSync)
// Loeschen=false + needsSync → termine[]

function simpleHash(str) {
  var hash = 5381;
  for (var i = 0; i < str.length; i++) {
    hash = ((hash << 5) + hash) + str.charCodeAt(i);
    hash = hash & hash;
  }
  return String(Math.abs(hash));
}

var items = $input.all();
var today = new Date();
today.setHours(0, 0, 0, 0);
var kundeMap = {};

for (var i = 0; i < items.length; i++) {
  var props        = items[i].json;
  var notionPageId = props.id || '';

  var kundenRaw = props.property_kunden || [];
  var kundenIds = Array.isArray(kundenRaw) ? kundenRaw : [kundenRaw];
  var validKunden = kundenIds.filter(Boolean);
  if (validKunden.length === 0) continue;

  // Löschen-Flag – Feldname bestätigt: property_loeschen
  var loeschen = props.property_loeschen === true;

  if (loeschen) {
    // Termin aus Confluence-Tabelle entfernen (via data-notion-id)
    for (var d = 0; d < validKunden.length; d++) {
      var kId = validKunden[d];
      if (!kundeMap[kId]) {
        kundeMap[kId] = { kundePageId: kId, termine: [], loescheIds: [] };
      }
      if (kundeMap[kId].loescheIds.indexOf(notionPageId) === -1) {
        kundeMap[kId].loescheIds.push(notionPageId);
      }
    }
    continue;
  }

  // Datum prüfen
  var datumObj = props.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start) { datumRaw = datumObj.start; }
  else if (typeof datumObj === 'string' && datumObj.length >= 10) { datumRaw = datumObj; }
  if (!datumRaw) continue;
  if (new Date(datumRaw.substring(0, 10)) < today) continue;

  var titel      = props.property_titel || props.name || 'Kein Titel';
  var ort        = props.property_ort   || '';
  var datumIso   = datumRaw.substring(0, 10);
  var dp         = datumIso.split('-');
  var datumStr   = dp[2] + '.' + dp[1] + '.' + dp[0];
  var uhrzeitStr = '';
  var tIdx       = datumRaw.indexOf('T');
  if (tIdx !== -1) { uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6); }

  var confluenceSync = props.property_confluence_sync === true;
  var lastSyncHash   = String(props.property_last_sync_hash || '').trim();
  var currentHash    = simpleHash(datumIso + '|' + titel);
  var needsSync      = !confluenceSync || (currentHash !== lastSyncHash);
  if (!needsSync) continue;

  for (var j = 0; j < validKunden.length; j++) {
    var kp = validKunden[j];
    if (!kundeMap[kp]) {
      kundeMap[kp] = { kundePageId: kp, termine: [], loescheIds: [] };
    }
    kundeMap[kp].termine.push({
      datumIso, datumStr, uhrzeitStr, titel, ort, notionPageId, currentHash
    });
  }
}

var result = [];
var keys = Object.keys(kundeMap);
for (var ki = 0; ki < keys.length; ki++) {
  var e = kundeMap[keys[ki]];
  if (e.termine.length === 0 && e.loescheIds.length === 0) continue;
  e.termine.sort(function(a,b){ return a.datumIso<b.datumIso?-1:a.datumIso>b.datumIso?1:0; });
  result.push({ json: e });
}
return result;

// ============================================================
// Code: Tabelle aufbauen (v7)
// Neu: loescheIds aus loopItem werden aus Tabelle entfernt
//      (anhand data-notion-id Attribut)
// Alle anderen Funktionen aus v6 bleiben erhalten.
// ============================================================

var page        = $json;
var loopItem    = $('Loop: Ein Kunde pro Durchlauf').item.json;
var neueTermine = loopItem.termine    || [];
var loescheIds  = loopItem.loescheIds || []; // notionPageIds zu löschender Termine

var esc = function(s) {
  return String(s || '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
};
var unesc = function(s) {
  return String(s || '')
    .replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>')
    .replace(/&quot;/g,'"').replace(/<[^>]+>/g,'');
};

var pageId       = page.id    || '';
var pageTitle    = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value)
  ? page.body.storage.value : '';

// ---------------------------------------------------------------
// Schritt 1: Panel finden
// ---------------------------------------------------------------
var panelTitles = [
  'N\u00e4chste Termine','N&auml;chste Termine',
  'N&#228;chste Termine','N&#xE4;chste Termine','N&#xe4;chste Termine'
];
var titleIdx = -1;
for (var ti = 0; ti < panelTitles.length; ti++) {
  titleIdx = html.indexOf(panelTitles[ti]);
  if (titleIdx !== -1) break;
}
if (titleIdx === -1) throw new Error('Heading "Nächste Termine" nicht gefunden. pageId:' + pageId);

var panelMacroTag = '<ac:structured-macro ac:name="panel"';
var panelStart    = html.indexOf(panelMacroTag, titleIdx);
if (panelStart === -1) throw new Error('Panel-Makro nicht gefunden. pageId:' + pageId);

var panelEndTag   = '</ac:structured-macro>';
var panelEnd      = html.indexOf(panelEndTag, panelStart);
if (panelEnd === -1) throw new Error('Panel-Ende nicht gefunden. pageId:' + pageId);
var panelEnd_full = panelEnd + panelEndTag.length;
var panelBlock    = html.substring(panelStart, panelEnd_full);

// ---------------------------------------------------------------
// Schritt 2: Bestehende Zeilen parsen
// ---------------------------------------------------------------
var today = new Date();
today.setHours(0,0,0,0);

function deToIso(s) {
  var p = String(s||'').trim().split('.');
  return p.length === 3 ? p[2]+'-'+p[1]+'-'+p[0] : '';
}
function isoToDate(iso) {
  var d = new Date(iso); d.setHours(0,0,0,0); return d;
}

// Set der zu löschenden notionPageIds
var loescheSet = {};
for (var li = 0; li < loescheIds.length; li++) {
  if (loescheIds[li]) loescheSet[loescheIds[li]] = true;
}

var byNotionId = {}; // notionPageId → terminObj
var byKey      = {}; // datumIso|titel → terminObj (Altbestand)

var trFullPattern = /<tr([^>]*)>([\s\S]*?)<\/tr>/g;
var trMatch;
trFullPattern.lastIndex = 0;
while ((trMatch = trFullPattern.exec(panelBlock)) !== null) {
  var trAttrs = trMatch[1];
  var rowHtml = trMatch[2];
  if (rowHtml.indexOf('<th') !== -1) continue;

  var notionIdMatch = trAttrs.match(/data-notion-id="([^"]+)"/);
  var notionPageId  = notionIdMatch ? notionIdMatch[1] : '';

  // Zu löschende Zeilen überspringen
  if (notionPageId && loescheSet[notionPageId]) continue;

  var tdValues = [];
  var tdPat = /<td[^>]*>([\s\S]*?)<\/td>/g;
  var tdMatch;
  while ((tdMatch = tdPat.exec(rowHtml)) !== null) {
    tdValues.push(unesc(tdMatch[1].trim()));
  }
  if (tdValues.length < 4) continue;

  var datumIso = deToIso(tdValues[0]);
  // Vergangene Termine entfernen
  if (datumIso && isoToDate(datumIso) < today) continue;

  var obj = {
    datumIso,
    datumStr:   tdValues[0],
    uhrzeitStr: tdValues[1],
    titel:      tdValues[2],
    ort:        tdValues[3],
    notionPageId
  };

  if (notionPageId) { byNotionId[notionPageId] = obj; }
  else              { byKey[datumIso+'|'+tdValues[2]] = obj; }
}

// ---------------------------------------------------------------
// Schritt 3: Neue/geänderte Termine einpflegen
// ---------------------------------------------------------------
for (var ni = 0; ni < neueTermine.length; ni++) {
  var nt = neueTermine[ni];
  if (!nt.datumIso || isoToDate(nt.datumIso) < today) continue;

  var newObj = {
    datumIso:    nt.datumIso,
    datumStr:    nt.datumStr,
    uhrzeitStr:  nt.uhrzeitStr,
    titel:       nt.titel,
    ort:         nt.ort,
    notionPageId: nt.notionPageId || ''
  };

  if (nt.notionPageId) {
    // Ersetzt bestehende Zeile ODER hängt neu an
    byNotionId[nt.notionPageId] = newObj;
  } else if (!byKey[nt.datumIso+'|'+nt.titel]) {
    byKey[nt.datumIso+'|'+nt.titel] = newObj;
  }
}

// ---------------------------------------------------------------
// Schritt 4: Zusammenführen + sortieren
// ---------------------------------------------------------------
var alleTermine = [];
var k1s = Object.keys(byNotionId);
for (var k1 = 0; k1 < k1s.length; k1++) alleTermine.push(byNotionId[k1s[k1]]);
var k2s = Object.keys(byKey);
for (var k2 = 0; k2 < k2s.length; k2++) alleTermine.push(byKey[k2s[k2]]);
alleTermine.sort(function(a,b){ return a.datumIso<b.datumIso?-1:a.datumIso>b.datumIso?1:0; });

// ---------------------------------------------------------------
// Schritt 5: Confluence Cloud-Tabelle aufbauen
// ---------------------------------------------------------------
var tableLocalId = 'termine-tbl-' + pageId + '-0001';
var headerRow = '<tr>'
  + '<th ac:local-id="'+tableLocalId+'-h1"><p><strong>Datum</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h2"><p><strong>Uhrzeit</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h3"><p><strong>Titel</strong></p></th>'
  + '<th ac:local-id="'+tableLocalId+'-h4"><p><strong>Ort</strong></p></th>'
  + '</tr>';

var dataRows = '';
for (var ri = 0; ri < alleTermine.length; ri++) {
  var t     = alleTermine[ri];
  var rowId = tableLocalId + '-r' + ri;
  var nAttr = t.notionPageId ? ' data-notion-id="'+esc(t.notionPageId)+'"' : '';
  dataRows += '<tr ac:local-id="'+rowId+'"'+nAttr+'>'
    + '<td ac:local-id="'+rowId+'-c1"><p>'+esc(t.datumStr)  +'</p></td>'
    + '<td ac:local-id="'+rowId+'-c2"><p>'+esc(t.uhrzeitStr)+'</p></td>'
    + '<td ac:local-id="'+rowId+'-c3"><p>'+esc(t.titel)     +'</p></td>'
    + '<td ac:local-id="'+rowId+'-c4"><p>'+esc(t.ort)       +'</p></td>'
    + '</tr>';
}

var tableHtml = alleTermine.length > 0
  ? '<table data-table-width="760" data-layout="default" ac:local-id="'+tableLocalId+'">'
    + '<tbody>'+headerRow+dataRows+'</tbody></table>'
  : '<p></p>';

var newRTB = '<ac:rich-text-body>' + tableHtml + '</ac:rich-text-body>';

// ---------------------------------------------------------------
// Schritt 6: Panel ersetzen
// ---------------------------------------------------------------
var selfClosing = '<ac:rich-text-body />';
var newPanelBlock;
if (panelBlock.indexOf(selfClosing) !== -1) {
  newPanelBlock = panelBlock.replace(selfClosing, newRTB);
} else {
  var rtbOpen  = '<ac:rich-text-body>';
  var rtbClose = '</ac:rich-text-body>';
  var rtbStart = panelBlock.indexOf(rtbOpen);
  var rtbEnd   = panelBlock.indexOf(rtbClose);
  if (rtbStart===-1||rtbEnd===-1) throw new Error('ac:rich-text-body nicht gefunden. pageId:'+pageId);
  newPanelBlock = panelBlock.substring(0,rtbStart) + newRTB
    + panelBlock.substring(rtbEnd+rtbClose.length);
}

html = html.substring(0,panelStart) + newPanelBlock + html.substring(panelEnd_full);
return { json: { pageId, pageTitle, newVersion: currentVersion+1, updatedHtml: html } };

// ============================================================
// Code: Sync-Items aufbereiten (v8)
// Mode: runOnceForAllItems
// Fix: Löschen-Flag wird NICHT zurückgesetzt (manuell gesetzt)
//      Nur ConfluenceSync=false + LastSyncHash='' für gelöschte Termine
// ============================================================

var loopItem   = $('Loop: Ein Kunde pro Durchlauf').item.json;
var termine    = loopItem.termine    || [];
var loescheIds = loopItem.loescheIds || [];

var result = [];

// Reguläre Termine: ConfluenceSync=true + Hash setzen
for (var i = 0; i < termine.length; i++) {
  var t = termine[i];
  if (!t.notionPageId) continue;
  result.push({
    json: {
      notionPageId: t.notionPageId,
      currentHash:  t.currentHash,
      _aktion:      'sync'
    }
  });
}

// Gelöschte Termine: nur ConfluenceSync=false + Hash leeren
// Löschen-Flag wird NICHT angefasst (bleibt true in Notion)
for (var d = 0; d < loescheIds.length; d++) {
  if (!loescheIds[d]) continue;
  result.push({
    json: {
      notionPageId: loescheIds[d],
      currentHash:  '',
      _aktion:      'geloescht'
    }
  });
}

if (result.length === 0) {
  result.push({ json: { notionPageId: '', currentHash: '', _aktion: 'noop' } });
}
return result;

// DEBUG: Output von Code: Nach Kunden aufteilen prüfen
// Bitte nach dem Test wieder entfernen
var items = $input.all();
var info = items.map(function(item) {
  return {
    kundePageId:    item.json.kundePageId,
    termineAnzahl:  (item.json.termine   || []).length,
    loescheAnzahl:  (item.json.loescheIds|| []).length,
    termineIds:     (item.json.termine   || []).map(function(t){ return t.notionPageId; }),
    loescheIds:     (item.json.loescheIds|| [])
  };
});
// Nicht werfen – einfach durchleiten mit Debug-Info
return items.map(function(item, i) {
  item.json._debug = info[i];
  return item;
});
